import React from 'react';
import { Link } from 'react-router-dom';

function HomePage() {
    return (
        <div>
            <h1>🐾 Pawnder 홈 페이지</h1>
            <Link to="/signup">회원가입</Link> | <Link to="/login">로그인</Link>
        </div>
    );
}

export default HomePage;
